-- PARTE 2/6 — conteúdo das iscas 1–6
update public.blog_templum_iscas set headline='Indicadores que <em>medem o que importa</em><br>na ISO 9001, não <em>o que é fácil</em>.', subhead='A norma exige medição. A consultoria mostra como sair dos indicadores genéricos e construir um conjunto enxuto, ligado à estratégia, que sustenta análise crítica de verdade.', benefits='["Critérios para escolher o que vale a pena <strong>medir de fato</strong>.","Indicadores ligados a <strong>objetivos do processo</strong>, não a achismo.","Como definir <strong>meta, periodicidade</strong> e responsável.","Quando o indicador <strong>perdeu sentido</strong> e precisa ser substituído."]'::jsonb, steps='[{"num":"01","title":"O que medir","text":"Critérios para separar indicador relevante de número que só enche relatório."},{"num":"02","title":"Indicadores de processo","text":"Como derivar do mapeamento, entradas, saídas, eficácia e eficiência."},{"num":"03","title":"Meta e periodicidade","text":"Definir alvo realista, ritmo de coleta e quem é o dono do número."},{"num":"04","title":"Análise e ação","text":"Do dashboard para a decisão, quando vira ação corretiva e quando vira melhoria."}]'::jsonb, cta_title='Pare de medir <em>pra mostrar</em>.<br>Comece a medir <em>pra decidir</em>.', cta_copy='O ebook foi escrito pra times que querem usar indicador como ferramenta de gestão, não como decoração de auditoria.', cta_items='["Leitura rápida, 45 min","Exemplos de indicadores por tipo de processo","Sem custo · sem compromisso"]'::jsonb, faq='[{"q":"Serve para quem ainda não tem ISO 9001?","a":"Sim. Os critérios de seleção de indicador valem para qualquer empresa que quer medir o que importa, com ou sem certificação."}]'::jsonb where slug='como-medir-processos-na-iso-9001';
update public.blog_templum_iscas set headline='Gestão de processos que <em>liga</em><br>contexto, execução e <em>resultado</em>.', subhead='Mapeamento de processo sem contexto vira diagrama parado na parede. Este guia mostra como começar pelo lugar certo e chegar até o indicador que move o ponteiro.', benefits='["Como ler o <strong>contexto da organização</strong> antes de mapear.","Diferença entre processo <strong>desenhado</strong> e processo <strong>vivo</strong>.","<strong>Responsabilidade</strong> clara, dono, executor, cliente interno.","Indicador que <strong>fecha o ciclo</strong> e alimenta a melhoria."]'::jsonb, steps='[{"num":"01","title":"Contexto","text":"Partes interessadas, ambiente externo e o que isso muda no mapeamento."},{"num":"02","title":"Cadeia de valor","text":"Como identificar processos primários, de apoio e gerenciais, e diferenciar."},{"num":"03","title":"Desenho com propósito","text":"Mapear com intenção: entradas, saídas, controles e recursos."},{"num":"04","title":"Responsabilidades","text":"Quem responde pelo quê. RACI aplicado sem virar burocracia."},{"num":"05","title":"Medição","text":"Indicadores de processo que conversam com a estratégia da empresa."},{"num":"06","title":"Melhoria","text":"Ciclo PDCA real, do desvio à ação, da ação à evidência."}]'::jsonb, cta_title='Processo bem desenhado<br>é o que <em>destrava resultado</em>.', cta_copy='O método neste ebook é o mesmo que aplicamos em consultoria com empresas de todos os portes, adaptado para você implementar internamente.', cta_items='["Aplicável a qualquer porte de empresa","Conecta ISO 9001 a outras normas","Sem custo · sem compromisso"]'::jsonb, faq='[{"q":"Preciso ter ISO 9001 para aproveitar?","a":"Não. O método de gestão por processos é independente da certificação, mas empresas em busca da ISO ganham um atalho enorme."}]'::jsonb where slug='gestao-de-processos-do-contexto-ao-resultado-que-importa';
update public.blog_templum_iscas set headline='Mapeamento de processos<br>que <em>sustenta</em> a ISO 27001<br>na auditoria.', subhead='Segurança da informação não é só firewall e política assinada. Sem mapeamento de processo, a auditoria encontra controle solto e ninguém sabe responder.', benefits='["Como definir <strong>escopo</strong> sem deixar fora o que importa.","<strong>Inventário de ativos</strong> ligado a processo, não a planilha solta.","Controles do <strong>Anexo A</strong> mapeados onde acontecem.","Evidência de implementação que <strong>auditor entende</strong>."]'::jsonb, steps='[{"num":"01","title":"Escopo","text":"Como delimitar sem cortar o que sustenta, e sem inflar o que não precisa."},{"num":"02","title":"Processos críticos","text":"Identificar onde a informação sensível trafega e quem responde por cada etapa."},{"num":"03","title":"Ativos por processo","text":"Inventário ligado à execução, não a planilha desconectada."},{"num":"04","title":"Controles aplicados","text":"Anexo A mapeado no ponto onde o risco acontece."},{"num":"05","title":"Evidências","text":"Registro que prova implementação, sem encenação na hora da auditoria."},{"num":"06","title":"Ciclo de melhoria","text":"Como integrar incidentes e análise crítica ao próximo ciclo."}]'::jsonb, cta_title='Certificação que <em>aguenta</em><br>a próxima auditoria.', cta_copy='Empresas que tratam ISO 27001 como entrega de documento sofrem na auditoria. Mapeamento real é a diferença entre passar e refazer.', cta_items='["Conformidade que se sustenta no dia a dia","Aplicável a SaaS, consultorias e indústrias","Sem custo · sem compromisso"]'::jsonb, faq='[{"q":"Serve para empresa pequena?","a":"Sim. O escopo pode ser enxuto sem perder integridade, o método é o mesmo, a escala muda."}]'::jsonb where slug='iso-27001-o-guia-completo-para-mapeamento-de-processos';
update public.blog_templum_iscas set headline='ISO 9001 que <em>gera</em> lucro,<br>não que vira <em>custo</em>.', subhead='Toda empresa certificada já ouviu que ISO é "chato e caro". Esse guia mostra como conduzir a implantação ou transição transformando exigência em diferencial de margem.', benefits='["<strong>Quick wins</strong> do primeiro mês, antes da auditoria.","Como evitar os <strong>erros caros</strong> de quem implementa pra cumprir tabela.","Ligação direta entre ISO e <strong>resultado financeiro</strong>.","<strong>Transição da versão</strong> sem perder certificação."]'::jsonb, steps='[{"num":"01","title":"Diagnóstico inicial","text":"O que sua empresa já faz que conta como conformidade, e o que ainda falta."},{"num":"02","title":"Decisões estratégicas","text":"Escopo, política e objetivos: o que define o resto do projeto."},{"num":"03","title":"Processos críticos","text":"Onde concentrar esforço para gerar resultado já no primeiro mês."},{"num":"04","title":"Quick wins financeiros","text":"Ajustes pequenos que reduzem retrabalho e perdas."},{"num":"05","title":"Auditoria com calma","text":"Como chegar pronto, sem maratona nas vésperas."},{"num":"06","title":"Pós-certificação","text":"Manter o sistema vivo, e crescendo em valor a cada ano."}]'::jsonb, cta_title='ISO 9001 paga a conta,<br>quando é <em>bem feita</em>.', cta_copy='Esse guia foi escrito por consultores que viram empresas economizarem 6% de margem só com gestão decente. O método é prático, sem teoria solta.', cta_items='["Casos reais de redução de retrabalho","Para empresas certificando ou em transição","Sem custo · sem compromisso"]'::jsonb, faq='[{"q":"Serve para empresa já certificada?","a":"Sim. Especialmente útil para quem precisa fazer transição de versão ou está sentindo que o sistema virou burocracia."}]'::jsonb where slug='e-book-lucre-com-a-iso';
update public.blog_templum_iscas set headline='NRs e ISO 45001 <em>no mesmo</em><br>sistema, sem duplicar<br><em>trabalho</em>.', subhead='Empresas que tratam NR e ISO 45001 como universos separados pagam duas vezes. Esse guia mostra como integrar em um sistema único, mantendo conformidade legal e certificação.', benefits='["<strong>Pontes</strong> entre NRs e cláusulas da ISO 45001.","Documento <strong>único</strong> que atende fiscalização e auditoria.","<strong>Treinamento</strong> e gestão de mudança integrados.","Plano que <strong>reduz pela metade</strong> o tempo de manutenção."]'::jsonb, steps='[{"num":"01","title":"Mapa de exigências","text":"Quais NRs aplicam à sua operação e como se conectam com cláusulas da ISO 45001."},{"num":"02","title":"Sistema integrado","text":"Um só sistema, atendendo NR, ISO e demais requisitos legais e contratuais."},{"num":"03","title":"Documentação única","text":"PGR, programas e procedimentos que servem para fiscalização e auditoria."},{"num":"04","title":"Cultura e capacitação","text":"Treinamento que une obrigação legal e prática operacional."},{"num":"05","title":"Monitoramento","text":"Indicadores que mostram conformidade e oportunidade de melhoria."},{"num":"06","title":"Auditoria pronta","text":"Como manter o sistema sempre auditável, sem maratona."}]'::jsonb, cta_title='Integrar é <em>economizar</em><br>esforço, custo e <em>tempo</em>.', cta_copy='Empresas que mantêm sistemas separados gastam o dobro em consultoria, treinamento e revisão. O guia mostra como unificar sem perder rigor.', cta_items='["Reduz custo de manutenção do SGSST","Aplicável a qualquer porte de empresa","Sem custo · sem compromisso"]'::jsonb, faq='[{"q":"Posso aplicar antes de buscar ISO 45001?","a":"Sim. A integração das NRs já melhora a gestão de SST, a certificação fica como próximo passo natural."}]'::jsonb where slug='integracao-nr-com-iso-45001-guia-completo-para-saude-e-seguranca';
update public.blog_templum_iscas set headline='Perigos e riscos sob a<br>ISO 45001, gestão <em>proativa</em>,<br>não <em>reativa</em>.', subhead='Identificar perigo só depois do acidente é o jeito caro de descobrir. A norma exige antecipação, e este ebook mostra o método para implementar.', benefits='["<strong>Identificação por processo</strong>, não por checklist genérico.","Matriz <strong>probabilidade × severidade</strong> com critérios claros.","Tratamento <strong>hierarquizado</strong>: eliminar, substituir, controlar, EPI.","<strong>Participação dos trabalhadores</strong> como exige a norma."]'::jsonb, steps='[{"num":"01","title":"Identificação","text":"Técnicas para mapear perigos onde o trabalho acontece, não na sala da gestão."},{"num":"02","title":"Avaliação de risco","text":"Critérios objetivos de probabilidade e severidade para comparar e priorizar."},{"num":"03","title":"Hierarquia de controle","text":"Eliminação, substituição, controle de engenharia, administrativo e EPI, nessa ordem."},{"num":"04","title":"Participação","text":"Como envolver o trabalhador para que a análise pegue o que a gestão não vê."},{"num":"05","title":"Plano de ação","text":"Responsável, prazo, recurso e evidência, sem ação no papel."},{"num":"06","title":"Monitoramento","text":"Reavaliação periódica e gatilhos que mantêm a análise viva."}]'::jsonb, cta_title='Acidente é <em>caro</em>.<br>Prevenir é <em>barato</em>.', cta_copy='Empresas que implementam o método deste ebook reduzem acidentes e auditorias virais, a gestão de risco passa a ser parte do dia a dia.', cta_items='["Aplicável independente de certificação","Casos reais de redução de TF e TG","Sem custo · sem compromisso"]'::jsonb, faq='[{"q":"Substitui o PGR?","a":"Não. Mas complementa, o PGR cumpre a NR-01, e a metodologia da ISO 45001 amplia para gestão estratégica de riscos."}]'::jsonb where slug='iso-45001-perigos-e-riscos-gestao-proativa-e-sustentavel';
